#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <regex.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char F[10001];
        scanf("%s", F);
        int Q;
        scanf("%d", &Q);
        while (Q--) {
            char IDS[2001];
            scanf("%s", IDS);
            // parse format string and create regular expression
            regex_t regex;
            int reti = regcomp(&regex, F, REG_EXTENDED);
            if (reti) {
                printf("Format does not conform\n");
            } else {
                reti = regexec(&regex, IDS, 0, NULL, 0);
                if (!reti) {
                    printf("Valid-ID\n");
                } else if (reti == REG_NOMATCH) {
                    printf("Invalid-ID\n");
                } else {
                    printf("Matches too long ID\n");
                }
                regfree(&regex);
            }
        }
    }
    return 0;
}

