public class Main {
    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String F = sc.next();
            int Q = sc.nextInt();
            while (Q-- > 0) {
                String IDS = sc.next();
                // parse format string and create regular expression
                java.util.regex.Pattern pattern = java.util.regex.Pattern.compile(F);
                java.util.regex.Matcher matcher = pattern.matcher(IDS);
                if (matcher.matches()) {
                    System.out.println("Valid-ID");
                } else {
                    System.out.println("Invalid-ID");
                }
            }
        }
    }
}

